package dev.pranav.reconnect.ui.picker

import android.content.ContentResolver
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import dev.pranav.reconnect.data.model.Contact
import dev.pranav.reconnect.data.model.ReconnectInterval
import dev.pranav.reconnect.data.repository.ContactRepository
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class ContactPickerUiState(
    val contacts: List<Contact> = emptyList(),
    val selectedIds: Set<String> = emptySet(),
    val intervals: Map<String, ReconnectInterval> = emptyMap(),
    val isLoading: Boolean = true,
    val searchQuery: String = ""
) {
    val filteredContacts: List<Contact>
        get() = if (searchQuery.isBlank()) contacts
        else contacts.filter { it.name.contains(searchQuery, ignoreCase = true) }

    val selectedCount: Int get() = selectedIds.size
}

class ContactPickerViewModel : ViewModel() {

    private val repository = ContactRepository()
    private val _uiState = MutableStateFlow(ContactPickerUiState())
    val uiState: StateFlow<ContactPickerUiState> = _uiState.asStateFlow()

    fun loadContacts(contentResolver: ContentResolver) {
        viewModelScope.launch(Dispatchers.IO) {
            val contacts = repository.getDeviceContacts(contentResolver)
            _uiState.update { it.copy(contacts = contacts, isLoading = false) }
        }
    }

    fun toggleContact(id: String) {
        _uiState.update { state ->
            val newSelected = state.selectedIds.toMutableSet()
            val newIntervals = state.intervals.toMutableMap()
            if (id in newSelected) {
                newSelected.remove(id)
                newIntervals.remove(id)
            } else {
                newSelected.add(id)
                newIntervals[id] = ReconnectInterval.MONTHLY
            }
            state.copy(selectedIds = newSelected, intervals = newIntervals)
        }
    }

    fun setInterval(id: String, interval: ReconnectInterval) {
        _uiState.update { state ->
            state.copy(intervals = state.intervals + (id to interval))
        }
    }

    fun updateSearch(query: String) {
        _uiState.update { it.copy(searchQuery = query) }
    }
}

package dev.pranav.reconnect.ui.picker

import android.content.ContentResolver
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import dev.pranav.reconnect.data.model.Contact
import dev.pranav.reconnect.data.model.ReconnectInterval
import dev.pranav.reconnect.data.repository.ContactRepository
import dev.pranav.reconnect.data.repository.SharedPrefsContactStore
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class ContactPickerUiState(
    val contacts: List<Contact> = emptyList(),
    val selectedIds: Set<String> = emptySet(),
    val intervals: Map<String, ReconnectInterval> = emptyMap(),
    val isLoading: Boolean = true,
    val searchQuery: String = ""
) {
    val filteredContacts: List<Contact>
        get() = if (searchQuery.isBlank()) contacts
        else contacts.filter { it.name.contains(searchQuery, ignoreCase = true) }

    val selectedCount: Int get() = selectedIds.size
}

class ContactPickerViewModel : ViewModel() {

    private val repository = ContactRepository()
    private val _uiState = MutableStateFlow(ContactPickerUiState())
    val uiState: StateFlow<ContactPickerUiState> = _uiState.asStateFlow()

    fun loadContacts(contentResolver: ContentResolver) {
        viewModelScope.launch(Dispatchers.IO) {
            val contacts = repository.getDeviceContacts(contentResolver)
            _uiState.update { it.copy(contacts = contacts, isLoading = false) }
        }
    }

    fun toggleContact(id: String) {
        _uiState.update { state ->
            val newSelected = state.selectedIds.toMutableSet()
            val newIntervals = state.intervals.toMutableMap()
            if (id in newSelected) {
                newSelected.remove(id)
                newIntervals.remove(id)
            } else {
                newSelected.add(id)
                newIntervals[id] = ReconnectInterval.MONTHLY
            }
            state.copy(selectedIds = newSelected, intervals = newIntervals)
        }
    }

    fun setInterval(id: String, interval: ReconnectInterval) {
        _uiState.update { state ->
            state.copy(intervals = state.intervals + (id to interval))
        }
    }

    fun updateSearch(query: String) {
        _uiState.update { it.copy(searchQuery = query) }
    }

    fun confirmSelection() {
        val state = _uiState.value
        val selected = state.contacts
            .filter { it.id in state.selectedIds }
            .map { contact ->
                contact.copy(
                    reconnectInterval = state.intervals[contact.id] ?: ReconnectInterval.MONTHLY,
                    isImportant = true
                )
            }
        SharedPrefsContactStore.addContacts(selected)
    }
}

package dev.pranav.reconnect.ui.home

import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.automirrored.filled.Send
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.runtime.saveable.rememberSaveable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.lifecycle.viewmodel.compose.viewModel
import dev.pranav.reconnect.data.model.Contact
import dev.pranav.reconnect.data.model.UpcomingEvent
import dev.pranav.reconnect.ui.theme.*

@Composable
fun HomeScreen(
    onContactClick: (String) -> Unit,
    innerPadding: PaddingValues = PaddingValues(),
    viewModel: HomeViewModel = viewModel()
) {
    val state by viewModel.uiState.collectAsState()
    var showAddSheet by rememberSaveable { mutableStateOf(false) }

    Scaffold(
        modifier = Modifier,
        contentWindowInsets = WindowInsets(0.dp),
        floatingActionButton = {
            FloatingActionButton(
                onClick = { showAddSheet = true },
                containerColor = GoldPrimary,
                contentColor = Color.White,
                shape = RoundedCornerShape(20.dp)
            ) {
                Icon(Icons.Default.Add, contentDescription = "Add contact")
            }
        },
        containerColor = Color.Transparent
    ) { scaffoldPadding ->
        LazyColumn(
            modifier = Modifier.fillMaxSize(),
            contentPadding = PaddingValues(
                top = innerPadding.calculateTopPadding(),
                bottom = innerPadding.calculateBottomPadding() + scaffoldPadding.calculateBottomPadding() + 80.dp
            ),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            item { HomeTopBar() }
            item { SectionHeader() }

            items(state.upcomingEvents) { event ->
                when (event) {
                    is UpcomingEvent.Birthday -> BirthdayBashCard(event, onContactClick)
                    is UpcomingEvent.CatchUp -> CatchUpCard(event, onContactClick)
                    is UpcomingEvent.TimelineReminder -> TimelineReminderCard(event, onContactClick)
                }
            }

            item { QuickCatchUpsHeader() }

            items(state.quickCatchUps) { (contact, subtitle) ->
                QuickCatchUpRow(contact, subtitle, onContactClick)
            }
        }
    }

    if (showAddSheet) {
        AddContactSheet(
            onDismiss = { showAddSheet = false },
            onSave = { name, phone, title, relationship, interval ->
                viewModel.addContact(name, phone, title, relationship, interval)
                showAddSheet = false
            }
        )
    }
}

@Composable
private fun HomeTopBar() {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 20.dp, vertical = 8.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Box(
            modifier = Modifier
                .size(40.dp)
                .background(GoldPrimary, CircleShape),
            contentAlignment = Alignment.Center
        ) {
            Icon(
                Icons.Default.BubbleChart,
                contentDescription = null,
                tint = Color.White,
                modifier = Modifier.size(22.dp)
            )
        }
        Spacer(Modifier.width(10.dp))
        Text(
            text = "ReConnect",
            fontFamily = UltraFamily,
            fontWeight = FontWeight.Normal,
            fontSize = 22.sp,
            color = GoldPrimary
        )
        Spacer(Modifier.weight(1f))
        IconButton(onClick = {}) {
            Icon(Icons.Default.Search, contentDescription = "Search", tint = CharcoalText)
        }
        Surface(
            modifier = Modifier.size(36.dp),
            shape = CircleShape,
            color = GoldPrimary.copy(alpha = 0.15f),
            border = androidx.compose.foundation.BorderStroke(2.dp, GoldPrimary)
        ) {
            Box(contentAlignment = Alignment.Center) {
                Icon(
                    Icons.Default.Person,
                    contentDescription = "Profile",
                    modifier = Modifier.size(20.dp),
                    tint = GoldPrimary
                )
            }
        }
    }
}

@Composable
private fun SectionHeader() {
    Text(
        text = "Upcoming\nConnections",
        style = MaterialTheme.typography.displayMedium,
