class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        SharedPrefsContactStore.init(this)
        enableEdgeToEdge()
        setContent {
            ReConnectTheme {
                ReConnectApp()
            }
        }
    }
}

enum class AppDestination(val label: String, val icon: ImageVector) {
    HOME("Home", Icons.Default.Home),
    CIRCLE("Circle", Icons.Default.People),
    EVENTS("Events", Icons.Default.CalendarMonth),
    SETTINGS("Settings", Icons.Default.Settings)
}

private const val PREFS_NAME = "reconnect_prefs"
private const val KEY_ONBOARDING_DONE = "onboarding_done"

@Composable
fun ReConnectApp() {
    val context = LocalContext.current
    val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
    val onboardingDone = prefs.getBoolean(KEY_ONBOARDING_DONE, false)

    var currentScreen by rememberSaveable { mutableStateOf(if (onboardingDone) "home" else "onboarding") }
    var detailContactId by rememberSaveable { mutableStateOf<String?>(null) }
    var selectedTab by rememberSaveable { mutableStateOf(AppDestination.HOME) }

    val showBottomNav = currentScreen == "home" || currentScreen == "detail"

    BackHandler(enabled = currentScreen == "detail") {
        currentScreen = "home"
        detailContactId = null
    }

    val background = Modifier
        .fillMaxSize()
        .background(Brush.verticalGradient(listOf(CreamBackground, Color.White)))

    if (!showBottomNav) {
        when (currentScreen) {
            "onboarding" -> OnboardingScreen(
                onPermissionGranted = { currentScreen = "picker" },
                onSkip = {
                    prefs.edit { putBoolean(KEY_ONBOARDING_DONE, true) }
                    currentScreen = "home"
                }
            )
            "picker" -> ContactPickerScreen(
                onContinue = {
                    prefs.edit { putBoolean(KEY_ONBOARDING_DONE, true) }
                    currentScreen = "home"
                },
                onSkip = {
                    prefs.edit { putBoolean(KEY_ONBOARDING_DONE, true) }
                    currentScreen = "home"
                }
            )
            "add" -> AddConnectionScreen(
                onBack = { currentScreen = "home" },
                onAdded = { currentScreen = "home" },
                onSyncContacts = { currentScreen = "picker" }
            )
        }
    } else {
        Scaffold(
            modifier = background,
            containerColor = Color.Transparent,
            bottomBar = {
                ReConnectBottomNav(
                    selected = selectedTab,
                    onSelect = { selectedTab = it }
                )
            }
        ) { innerPadding ->
            when {
                currentScreen == "detail" && detailContactId != null -> {
                    PersonDetailScreen(
                        contactId = detailContactId!!,
                        onBack = {
                            currentScreen = "home"
                            detailContactId = null
                        },
                        innerPadding = innerPadding
                    )
                }
                else -> {
                    HomeScreen(
                        onContactClick = { id ->
                            detailContactId = id
                            currentScreen = "detail"
                        },
                        onAddClick = { currentScreen = "add" },
                        innerPadding = innerPadding
                    )
                }
            }
        }
    }
}

@Composable
private fun ReConnectBottomNav(
    selected: AppDestination,
    onSelect: (AppDestination) -> Unit
) {
    Surface(
        color = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f),
        shadowElevation = 8.dp,
        modifier = Modifier.fillMaxWidth()
    ) {
        Box(modifier = Modifier.fillMaxWidth()) {
            Box(
                modifier = Modifier
                    .width(40.dp)
                    .height(3.dp)
                    .background(MediumGray.copy(alpha = 0.4f), RoundedCornerShape(2.dp))
                    .align(Alignment.TopCenter)
            )
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .navigationBarsPadding()
                    .padding(horizontal = 24.dp, vertical = 10.dp),
                horizontalArrangement = Arrangement.SpaceAround,
                verticalAlignment = Alignment.CenterVertically
            ) {
                AppDestination.entries.forEach { dest ->
                    val isSelected = dest == selected
                    val tint = if (isSelected) GoldPrimary else CharcoalText.copy(alpha = 0.45f)
                    Column(
                        modifier = Modifier
                            .clickable(
                                interactionSource = null,
                                indication = null,
                                onClick = { onSelect(dest) }
                            )
                            .padding(horizontal = 12.dp, vertical = 4.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(2.dp)
                    ) {
                        Icon(dest.icon, contentDescription = dest.label, tint = tint, modifier = Modifier.size(24.dp))
                        Text(
                            text = dest.label.uppercase(),
                            color = tint,
                            fontWeight = FontWeight.Bold,
                            fontSize = 9.sp,
                            letterSpacing = 0.8.sp
                        )
                    }
                }
            }
        }
    }
}

package dev.pranav.reconnect.data.model
enum class MomentCategory { DINING, ART, OUTDOORS, GENERAL }
data class PastMoment( val id: String, val title: String, val description: String, val dateLabel: String, val category: MomentCategory, val imageUris: List<String> = emptyList() )

package dev.pranav.reconnect.data.model
enum class MomentCategory { DINING, ART, OUTDOORS, GENERAL }
data class PastMoment( val id: String, val contactId: String = "", val title: String, val description: String, val dateLabel: String, val category: MomentCategory, val imageUris: List<String> = emptyList() )

package dev.pranav.reconnect.data.repository

import android.content.Context
import android.content.SharedPreferences
import androidx.core.content.edit
import dev.pranav.reconnect.data.model.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import org.json.JSONArray
import org.json.JSONObject

object SharedPrefsContactStore : IContactStore {

    private const val PREFS_NAME = "reconnect_contact_store"
    private const val KEY_CONTACTS = "contacts"
    private const val KEY_MOMENTS = "moments"
    private const val KEY_SEEDED = "seeded"

    private lateinit var prefs: SharedPreferences

    private val _contacts = MutableStateFlow<List<Contact>>(emptyList())
    override val contacts: StateFlow<List<Contact>> = _contacts.asStateFlow()

    private val _moments = MutableStateFlow<List<PastMoment>>(emptyList())
    override val moments: StateFlow<List<PastMoment>> = _moments.asStateFlow()

    fun init(context: Context) {
        if (::prefs.isInitialized) return
        prefs = context.applicationContext.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        if (!prefs.getBoolean(KEY_SEEDED, false)) {
            seedSampleData()
        } else {
            _contacts.value = loadContacts()
            _moments.value = loadMoments()
        }
    }

    private fun seedSampleData() {
        val repository = ContactRepository()
        _contacts.value = repository.getSampleContacts()
        _moments.value = repository.getSamplePastMoments().map { it.copy(contactId = "1") }
        persistContacts()
        persistMoments()
        prefs.edit { putBoolean(KEY_SEEDED, true) }
    }

    override fun addContacts(newContacts: List<Contact>) {
        val existingIds = _contacts.value.map { it.id }.toSet()
        val toAdd = newContacts.filter { it.id !in existingIds }
        if (toAdd.isEmpty()) return
        _contacts.value = _contacts.value + toAdd
        persistContacts()
    }

    override fun addContact(contact: Contact) {
        if (_contacts.value.any { it.id == contact.id }) return
        _contacts.value = _contacts.value + contact
        persistContacts()
    }

    override fun addMoment(moment: PastMoment) {
        _moments.value = listOf(moment) + _moments.value
        persistMoments()
    }

    override fun getMomentsFor(contactId: String): List<PastMoment> =
        _moments.value.filter { it.contactId == contactId }

    private fun persistContacts() {
        val arr = JSONArray()
        _contacts.value.forEach { arr.put(it.toJson()) }
        prefs.edit { putString(KEY_CONTACTS, arr.toString()) }
    }

    private fun persistMoments() {
        val arr = JSONArray()
        _moments.value.forEach { arr.put(it.toJson()) }
        prefs.edit { putString(KEY_MOMENTS, arr.toString()) }
    }

    private fun loadContacts(): List<Contact> {
        val json = prefs.getString(KEY_CONTACTS, null) ?: return emptyList()
        return try {
            val arr = JSONArray(json)
            (0 until arr.length()).map { arr.getJSONObject(it).toContact() }
        } catch (e: Exception) {
            emptyList()
        }
    }

    private fun loadMoments(): List<PastMoment> {
        val json = prefs.getString(KEY_MOMENTS, null) ?: return emptyList()
        return try {
            val arr = JSONArray(json)
            (0 until arr.length()).map { arr.getJSONObject(it).toPastMoment() }
        } catch (e: Exception) {
            emptyList()
        }
    }

    private fun Contact.toJson(): JSONObject = JSONObject().apply {
        put("id", id)
        put("name", name)
        put("title", title)
        put("relationship", relationship)
        photoUri?.let { put("photoUri", it) }
        put("phoneNumber", phoneNumber)
        put("isActive", isActive)
        put("isImportant", isImportant)
        put("reconnectInterval", reconnectInterval.name)
    }

    private fun JSONObject.toContact(): Contact = Contact(
        id = getString("id"),
        name = getString("name"),
        title = optString("title", ""),
        relationship = optString("relationship", ""),
        photoUri = optString("photoUri").takeIf { it.isNotBlank() },
        phoneNumber = optString("phoneNumber", ""),
        isActive = optBoolean("isActive", false),
        isImportant = optBoolean("isImportant", false),
        reconnectInterval = try {
            ReconnectInterval.valueOf(optString("reconnectInterval", ReconnectInterval.MONTHLY.name))
        } catch (e: Exception) {
            ReconnectInterval.MONTHLY
        }
    )

    private fun PastMoment.toJson(): JSONObject = JSONObject().apply {
        put("id", id)
        put("contactId", contactId)
        put("title", title)
        put("description", description)
        put("dateLabel", dateLabel)
        put("category", category.name)
        val imgArr = JSONArray()
        imageUris.forEach { imgArr.put(it) }
        put("imageUris", imgArr)
    }

    private fun JSONObject.toPastMoment(): PastMoment = PastMoment(
        id = getString("id"),
        contactId = optString("contactId", ""),
        title = getString("title"),
        description = optString("description", ""),
        dateLabel = optString("dateLabel", ""),
        category = try {
            MomentCategory.valueOf(optString("category", MomentCategory.GENERAL.name))
        } catch (e: Exception) {
            MomentCategory.GENERAL
        },
        imageUris = run {
            val arr = optJSONArray("imageUris") ?: return@run emptyList()
            (0 until arr.length()).map { arr.getString(it) }
        }
    )
}

